package org.apache.commons.math.dfp.steps;

import org.apache.commons.math.dfp.Dfp;
import org.apache.commons.math.dfp.DfpField;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

public class StepDefs {

    private DfpField field;
    private Dfp dfpValue;
    private double result;

    @Given("a Dfp field with 100 digits")
    public void a_Dfp_field_with_100_digits() {
        field = new DfpField(100);
    }

    @When("I create a Dfp instance from value {double}")
    public void i_create_a_Dfp_instance_from_value(double value) {
        dfpValue = field.newDfp(value);
