    @When("I get the default zero value from the field")
    public void i_get_the_default_zero_value_from_the_field() {
        dfpValue = field.getZero();
    }

    @Then("the toDouble conversion should return {double}")
    public void the_toDouble_conversion_should_return(double expected) {
        result = dfpValue.toDouble();
        assertEquals(expected, result, 0.0);
